const content = $input.first().json.choices[0].message.content;
const clean = content.replace(/```json|```/g, "").trim();
const parsed = JSON.parse(clean);

const sourceNode = $input.first().json.Lead_Name ? $input.first() : null;
const mapNode = (() => {
  try { return $('Map Lead Data').item.json; } catch(e) {}
  try { return $('Map Tally Data').item.json; } catch(e) {}
  return {};
})();

return [{
  json: {
    intent: parsed.intent,
    urgency: parsed.urgency,
    lead_score: parsed.lead_score,
    lead_tag: parsed.lead_tag.trim(),
    property_interest: parsed.property_interest,
    budget: parsed.budget,
    recommended_action: parsed.recommended_action,
    reply_message: parsed.reply_message,
    Lead_Name: mapNode.Lead_Name,
    Contact: mapNode.Contact,
    Message_Text: mapNode.Message_Text,
    Platform: mapNode.Platform,
    Timestamp: mapNode.Timestamp
  }
}];

